import datetime
import matplotlib.pyplot as plt
import pandas as pd
import numpy as np

class Workout:
    def __init__(self, date, sport, duration, distance=None, calories=None, heart_rate_data=None, pace=None):
        self.date = date
        self.sport = sport
        self.duration = duration  # in seconds
        self.distance = distance  # in meters
        self.calories = calories
        self.heart_rate_data = heart_rate_data  # list of (timestamp, heart_rate) tuples
        self.pace = pace # in seconds per meter

    def __repr__(self):
        return f"Workout({self.date}, {self.sport}, {self.duration}, {self.distance}, {self.calories}, {self.pace})"

class WorkoutTracker:
    def __init__(self):
        self.workouts = []
        self.nutrition_data = [] # Placeholder for nutrition data

    def import_strava(self, strava_data):
        # Placeholder for Strava import logic
        # Strava data assumed to be a list of dictionaries
        for item in strava_data:
            try:
                date = datetime.datetime.strptime(item['start_date_local'][:10], '%Y-%m-%d').date()
                sport = item['type']
                duration = item['elapsed_time']
                distance = item['distance']
                calories = item['calories'] if 'calories' in item else None
                #Simplified pace calculation
                pace = duration / distance if distance > 0 else None

                self.workouts.append(Workout(date, sport, duration, distance, calories, pace=pace))
            except Exception as e:
                print(f"Error importing Strava data: {e}")

    def import_polar_flow(self, polar_data):
        # Placeholder for Polar Flow import logic
        # Polar data assumed to be a list of dictionaries
        for item in polar_data:
            try:
                date = datetime.datetime.strptime(item['date'][:10], '%Y-%m-%d').date()
                sport = item['sport']
                duration = item['duration']
                distance = item['distance']
                calories = item['calories'] if 'calories' in item else None
                heart_rate_data = item.get('heart_rate_data') #Assumes a list of (timestamp, heart_rate)
                #Simplified pace calculation
                pace = duration / distance if distance > 0 else None

                self.workouts.append(Workout(date, sport, duration, distance, calories, heart_rate_data, pace=pace))
            except Exception as e:
                print(f"Error importing Polar Flow data: {e}")

    def import_myfitnesspal(self, mfp_data):
        # Placeholder for MyFitnessPal import logic
        # MFP data assumed to be a list of dictionaries
        self.nutrition_data.extend(mfp_data)

    def filter_by_sport(self, sport):
        return [workout for workout in self.workouts if workout.sport == sport]

    def calculate_total_mileage(self, sport=None):
        if sport:
            filtered_workouts = self.filter_by_sport(sport)
        else:
            filtered_workouts = self.workouts
        total_meters = sum(workout.distance for workout in filtered_workouts if workout.distance is not None)
        return total_meters / 1609.34  # Convert meters to miles

    def aggregate_heart_rate_zones(self):
        zones = {'Zone 1': 0, 'Zone 2': 0, 'Zone 3': 0, 'Zone 4': 0, 'Zone 5': 0}
        for workout in self.workouts:
            if workout.heart_rate_data:
                for timestamp, hr in workout.heart_rate_data:
                    if 50 <= hr <= 60:
                        zones['Zone 1'] += 1 # Assuming 1 second intervals
                    elif 60 < hr <= 70:
                        zones['Zone 2'] += 1
                    elif 70 < hr <= 80:
                        zones['Zone 3'] += 1
                    elif 80 < hr <= 90:
                        zones['Zone 4'] += 1
                    elif hr > 90:
                        zones['Zone 5'] += 1
        return zones

    def generate_progress_graph(self, metric='mileage', sport=None):
        dates = []
        values = []

        if sport:
            filtered_workouts = self.filter_by_sport(sport)
        else:
            filtered_workouts = self.workouts

        if metric == 'mileage':
            for workout in filtered_workouts:
                if workout.distance is not None:
                    dates.append(workout.date)
                    values.append(workout.distance / 1609.34) #meters to miles
        elif metric == 'pace':
            for workout in filtered_workouts:
                if workout.pace is not None:
                    dates.append(workout.date)
                    values.append(workout.pace * 1609.34) #seconds per mile
        else:
            print("Invalid metric. Choose 'mileage' or 'pace'.")
            return

        if not dates:
            print("No data available for the selected metric and sport.")
            return

        df = pd.DataFrame({'Date': dates, 'Value': values})
        df = df.groupby('Date')['Value'].sum().reset_index() #Aggregate multiple workouts on the same day
        df = df.sort_values('Date')

        plt.figure(figsize=(10, 6))
        plt.plot(df['Date'], df['Value'])
        plt.xlabel("Date")
        plt.ylabel(metric.capitalize())
        plt.title(f"{metric.capitalize()} Progress")
        plt.grid(True)
        plt.show()

