                        zones['Zone 3'] += 1
                    elif 80 < heart_rate <= 90:
                        zones['Zone 4'] += 1
                    elif heart_rate > 90:
                        zones['Zone 5'] += 1
        return zones

    def generate_workout_summary(self, sort_by='date'):
        """Generates a summary of workouts, sorted by the specified criteria."""
        if not self.workouts:
            return "No workouts recorded yet."

        if sort_by == 'date':
            sorted_workouts = sorted(self.workouts, key=lambda x: x.date)
        elif sort_by == 'distance':
            sorted_workouts = sorted(self.workouts, key=lambda x: x.distance if x.distance is not None else 0, reverse=True)
        elif sort_by == 'duration':
            sorted_workouts = sorted(self.workouts, key=lambda x: x.duration, reverse=True)
        else:
            return "Invalid sort criteria."

        summary = "Workout Summary:\n"
        for workout in sorted_workouts:
            summary += str(workout) + "\n"
        return summary

    def plot_progress(self, metric='distance'):
        """Plots progress over time based on the specified metric."""
        if not self.workouts:
            print("No workout data available to plot.")
            return

        dates = [workout.date for workout in self.workouts]
        if metric == 'distance':
            values = [workout.distance if workout.distance is not None else 0 for workout in self.workouts]
            plt.ylabel('Distance (meters)')
        elif metric == 'pace':
            # Calculate pace (minutes per km)
            paces = []
            for workout in self.workouts:
                if workout.distance and workout.duration:
                    pace_seconds_per_km = (workout.duration / workout.distance) * 1000
                    pace_minutes_per_km = pace_seconds_per_km / 60
                    paces.append(pace_minutes_per_km)
                else:
                    paces.append(None)  # Handle workouts without distance/duration
            values = [pace if pace is not None else np.nan for pace in paces] # Use NaN for missing values
            plt.ylabel('Pace (minutes/km)')
        else:
            print("Invalid metric for plotting.")
            return

        plt.plot(dates, values, marker='o')
        plt.xlabel('Date')
        plt.title(f'Progress Over Time ({metric})')
        plt.xticks(rotation=45)
        plt.tight_layout()
