        self.workouts = []
        self.nutrition_data = [] # Placeholder for nutrition data

    def add_workout(self, workout):
        self.workouts.append(workout)

    def add_nutrition_data(self, date, calories, protein, carbs, fat):
        self.nutrition_data.append({"date": date, "calories": calories, "protein": protein, "carbs": carbs, "fat": fat})

    def import_strava_data(self, strava_data):
        # Simulate Strava import (replace with actual API calls)
        for activity in strava_data:
            date = datetime.datetime.strptime(activity['start_date_local'][:10], '%Y-%m-%d').date()
            sport = activity['type']
            duration = activity['elapsed_time']
            distance = activity['distance']
            self.add_workout(Workout(date, sport, duration, distance))

    def import_polar_flow_data(self, polar_data):
        # Simulate Polar Flow import (replace with actual API calls)
        for training_session in polar_data:
            date = datetime.datetime.strptime(training_session['startTime'][:10], '%Y-%m-%d').date()
            sport = training_session['sport']
            duration = training_session['duration']
            distance = training_session['distance']
            heart_rate_data = training_session.get('heart_rate_data', []) # Assume Polar provides HR data
            self.add_workout(Workout(date, sport, duration, distance, heart_rate_data=heart_rate_data))

    def import_myfitnesspal_data(self, mfp_data):
        # Simulate MyFitnessPal import
        for entry in mfp_data:
            date = datetime.datetime.strptime(entry['date'], '%Y-%m-%d').date()
            calories = entry['calories']
            protein = entry['protein']
            carbs = entry['carbs']
            fat = entry['fat']
            self.add_nutrition_data(date, calories, protein, carbs, fat)

    def get_workouts_by_sport(self, sport):
        return [workout for workout in self.workouts if workout.sport == sport]

    def calculate_total_mileage(self, sport=None):
        total_distance_meters = 0
        if sport:
            workouts = self.get_workouts_by_sport(sport)
        else:
            workouts = self.workouts

        for workout in workouts:
            if workout.distance:
                total_distance_meters += workout.distance
        return total_distance_meters / 1609.34  # Convert meters to miles

    def calculate_total_time(self, sport=None):
        total_time_seconds = 0
        if sport:
            workouts = self.get_workouts_by_sport(sport)
        else:
            workouts = self.workouts

        for workout in workouts:
            total_time_seconds += workout.duration
        return total_time_seconds / 3600 # Convert seconds to hours

    def analyze_heart_rate_zones(self):
        zones = {"Zone 1": 0, "Zone 2": 0, "Zone 3": 0, "Zone 4": 0, "Zone 5": 0}
        for workout in self.workouts:
            if workout.heart_rate_data:
                for timestamp, heart_rate in workout.heart_rate_data:
                    if heart_rate < 120:
                        zones["Zone 1"] += 1  # Example thresholds, adjust as needed
                    elif heart_rate < 140:
                        zones["Zone 2"] += 1
                    elif heart_rate < 160:
                        zones["Zone 3"] += 1
                    elif heart_rate < 180:
                        zones["Zone 4"] += 1
                    else:
                        zones["Zone 5"] += 1
        return zones

