        date_range = pd.date_range(start=dates[0], end=dates[-1])
        data = []
        for date in date_range:
            daily_mileage = 0
            daily_time = 0
            for workout in self.workouts:
                if workout.date == date.date():
                    if workout.distance:
                        daily_mileage += workout.distance / 1609.34
                    daily_time += workout.duration / 3600
            data.append([date, daily_mileage, daily_time])

        df = pd.DataFrame(data, columns=['Date', 'Mileage', 'Time'])
        df = df.set_index('Date')

        if metric == "mileage":
            plt.figure(figsize=(12, 6))
            plt.plot(df.index, df['Mileage'])
            plt.xlabel("Date")
            plt.ylabel("Mileage (miles)")
            plt.title("Progress by Mileage")
            plt.grid(True)
            plt.show()
        elif metric == "time":
