        # Basic example - assumes strava_data is a list of dictionaries
        # with keys like 'date', 'sport', 'distance', 'time', 'average_heartrate'
        for workout in strava_data:
            date = datetime.datetime.strptime(workout['date'], '%Y-%m-%d') # Assuming date format
            if date not in self.data:
                self.data[date] = []
            self.data[date].append({
                'source': 'Strava',
                'sport': workout['sport'],
                'distance': workout['distance'],
                'time': workout['time'],
                'average_heartrate': workout['average_heartrate']
            })
        if 'Strava' not in self.sources:
            self.sources.append('Strava')
        print("Strava data imported.")

    def import_polar_flow(self, polar_data):
        """Imports workout data from Polar Flow.  Polar_data should be a list of dictionaries."""
        # Similar structure to Strava import
        for workout in polar_data:
            date = datetime.datetime.strptime(workout['date'], '%Y-%m-%d') # Assuming date format
            if date not in self.data:
                self.data[date] = []
            self.data[date].append({
                'source': 'Polar Flow',
                'sport': workout['sport'],
                'distance': workout['distance'],
                'time': workout['time'],
                'average_heartrate': workout['average_heartrate']
            })
        if 'Polar Flow' not in self.sources:
            self.sources.append('Polar Flow')
        print("Polar Flow data imported.")

    def import_myfitnesspal(self, nutrition_data):
        """Imports nutrition data from MyFitnessPal. nutrition_data should be a list of dictionaries."""
        for entry in nutrition_data:
            date = datetime.datetime.strptime(entry['date'], '%Y-%m-%d')
            if date not in self.nutrition_data:
                self.nutrition_data[date] = []
            self.nutrition_data[date].append({
                'source': 'MyFitnessPal',
                'calories': entry['calories'],
                'protein': entry['protein'],
                'carbs': entry['carbs'],
                'fat': entry['fat']
            })
        if 'MyFitnessPal' not in self.sources:
            self.sources.append('MyFitnessPal')
        print("MyFitnessPal data imported.")

    def filter_by_sport(self, sport):
