        filtered_data = {}
        for date, workouts in self.data.items():
            filtered_workouts = [w for w in workouts if w['sport'] == sport]
            if filtered_workouts:
                filtered_data[date] = filtered_workouts
        return filtered_data

    def aggregate_mileage(self, sport=None):
