        for date, workouts in data_to_use.items():
            total_mileage = sum([w['distance'] for w in workouts])
            mileage_data[date] = total_mileage
        return mileage_data

    def aggregate_heart_rate_zones(self):
        """Aggregates time spent in different heart rate zones."""
        # Example heart rate zones (adjust as needed)
        zones = {
            'Zone 1': (0, 120),  # Example: Light activity
            'Zone 2': (120, 140), # Example: Moderate activity
            'Zone 3': (140, 160), # Example: Tempo
            'Zone 4': (160, 180), # Example: Threshold
            'Zone 5': (180, 220)  # Example: Maximum
        }

        zone_times = {zone: 0 for zone in zones}

        for date, workouts in self.data.items():
            for workout in workouts:
                avg_hr = workout['average_heartrate']
                time = workout['time'] # Assuming time is in minutes
                for zone, (lower, upper) in zones.items():
                    if lower <= avg_hr < upper:
                        zone_times[zone] += time

        return zone_times

    def plot_progress(self, metric='mileage'):
