            plt.xlabel("Date")
            plt.ylabel("Average Pace (time/distance)")
            plt.title("Pace Over Time")
            plt.xticks(rotation=45)
            plt.tight_layout()
            plt.show()
        else:
            print("Invalid metric. Choose 'mileage' or 'pace'.")

    def display_dashboard(self):
        """Displays a summary dashboard of workout and nutrition information."""
        print("--- Workout Dashboard ---")
        print(f"Data Sources: {', '.join(self.sources)}")

        # Example: Display total mileage
