import datetime
import matplotlib.pyplot as plt
import pandas as pd
import numpy as np

class WorkoutApp:
    def __init__(self):
        self.data = {}  # Store workout data from different sources
        self.sources = {} # Store source names for each workout
        self.nutrition_data = {} # Store nutrition data
        self.source_modules = {} # Store imported source modules
        self.available_sources = ["Strava", "Polar Flow", "MyFitnessPal"]

    def register_source(self, source_name, module):
        """Registers a data source module."""
        if source_name in self.available_sources:
            self.source_modules[source_name] = module
        else:
            print(f"Error: Source {source_name} is not supported.")

    def import_data(self, source, filepath=None, data=None):
        """Imports workout data from a specified source."""
        if source not in self.source_modules:
            print(f"Error: Source {source} is not registered.")
            return

        try:
            if filepath:
                imported_data = self.source_modules[source].import_data(filepath)
            elif data:
                imported_data = self.source_modules[source].import_data(data=data)
            else:
                print("Error: Must provide either filepath or data.")
                return

            if not isinstance(imported_data, list):
                imported_data = [imported_data] # Ensure it's a list

            for workout in imported_data:
                workout_id = workout.get("workout_id", len(self.data) + 1) # Generate ID if missing
                self.data[workout_id] = workout
                self.sources[workout_id] = source # Store the source
            print(f"Successfully imported data from {source}.")

        except Exception as e:
            print(f"Error importing data from {source}: {e}")

    def import_nutrition_data(self, source, filepath=None, data=None):
        """Imports nutrition data from a specified source."""
        if source not in self.source_modules:
            print(f"Error: Source {source} is not registered.")
            return

        try:
            if filepath:
                imported_data = self.source_modules[source].import_nutrition_data(filepath)
            elif data:
                imported_data = self.source_modules[source].import_nutrition_data(data=data)
            else:
                print("Error: Must provide either filepath or data.")
                return

            if not isinstance(imported_data, list):
                imported_data = [imported_data]

            for entry in imported_data:
                entry_id = entry.get("entry_id", len(self.nutrition_data) + 1)
                self.nutrition_data[entry_id] = entry
            print(f"Successfully imported nutrition data from {source}.")

        except Exception as e:
            print(f"Error importing nutrition data from {source}: {e}")

    def filter_workouts(self, sport=None, date_range=None, source=None):
        """Filters workouts based on specified criteria."""
        filtered_data = {}
        for workout_id, workout in self.data.items():
            if sport and workout.get("sport") != sport:
                continue
            if source and self.sources[workout_id] != source:
                continue
            if date_range:
                start_date, end_date = date_range
                workout_date = datetime.datetime.strptime(workout.get("start_time").split('T')[0], '%Y-%m-%d').date()
                if not (start_date <= workout_date <= end_date):
                    continue
            filtered_data[workout_id] = workout
        return filtered_data

    def aggregate_heart_rate_zones(self, workouts=None):
        """Aggregates time spent in different heart rate zones."""
        if workouts is None:
            workouts = self.data
        zone_data = {}
        for workout_id, workout in workouts.items():
            if "heart_rate_zones" in workout:
                for zone, duration in workout["heart_rate_zones"].items():
                    if zone not in zone_data:
                        zone_data[zone] = 0
                    zone_data[zone] += duration
        return zone_data

    def calculate_total_mileage(self, workouts=None):
        """Calculates total mileage from a set of workouts."""
        if workouts is None:
            workouts = self.data
        total_mileage = 0
        for workout_id, workout in workouts.items():
            total_mileage += workout.get("distance", 0) / 1609.34  # Convert meters to miles
        return total_mileage

    def calculate_average_pace(self, workouts=None):
        """Calculates average pace from a set of workouts (minutes per mile)."""
        if workouts is None:
            workouts = self.data
        total_time = 0
        total_distance = 0
        for workout_id, workout in workouts.items():
            total_time += workout.get("elapsed_time", 0)  # in seconds
            total_distance += workout.get("distance", 0) # in meters

        if total_distance == 0:
            return 0

        total_distance_miles = total_distance / 1609.34
        average_pace_seconds_per_mile = total_time / total_distance_miles
        average_pace_minutes_per_mile = average_pace_seconds_per_mile / 60

        return average_pace_minutes_per_mile

    def generate_progress_graph(self, metric="mileage"):
        """Generates a graph of progress over time, either by mileage or pace."""
        dates = []
        values = []

        sorted_workouts = sorted(self.data.items(), key=lambda item: item[1].get("start_time"))

        for workout_id, workout in sorted_workouts:
            try:
                date = datetime.datetime.strptime(workout.get("start_time").split('T')[0], '%Y-%m-%d').date()
            except:
                continue

            if metric == "mileage":
                value = workout.get("distance", 0) / 1609.34  # Convert meters to miles
            elif metric == "pace":
                elapsed_time = workout.get("elapsed_time", 0)
                distance = workout.get("distance", 0)
                if distance == 0:
                    value = np.nan
                else:
                    distance_miles = distance / 1609.34
                    pace_seconds_per_mile = elapsed_time / distance_miles
                    value = pace_seconds_per_mile / 60 # minutes per mile
            else:
                print("Invalid metric. Choose 'mileage' or 'pace'.")
                return

            dates.append(date)
            values.append(value)

        df = pd.DataFrame({'Date': dates, metric.capitalize(): values})
        df = df.groupby('Date')[metric.capitalize()].sum().reset_index()

        plt.figure(figsize=(10, 6))
        plt.plot(df['Date'], df[metric.capitalize()], marker='o')
        plt.xlabel("Date")
        plt.ylabel(metric.capitalize())
        plt.title(f"Progress Over Time ({metric.capitalize()})")
        plt.grid(True)
        plt.xticks(rotation=45)
        plt.tight_layout()
        plt.show()

    def display_dashboard(self, sport=None, date_range=None, source=None):
        """Displays a dashboard of workout and nutrition information."""
        filtered_workouts = self.filter_workouts(sport, date_range, source)

        print("\n--- Workout Dashboard ---")
        if sport:
            print(f"Sport: {sport}")
        if date_range:
            print(f"Date Range: {date_range[0]} - {date_range[1]}")
        if source:
            print(f"Source: {source}")

        print(f"Total Workouts: {len(filtered_workouts)}")
        total_mileage = self.calculate_total_mileage(filtered_workouts)
        print(f"Total Mileage: {total_mileage:.2f} miles")
        average_pace = self.calculate_average_pace(filtered_workouts)
        print(f"Average Pace: {average_pace:.2f} minutes/mile")

        heart_rate_zones = self.aggregate_heart_rate_zones(filtered_workouts)
        print("\n--- Heart Rate Zones ---")
        for zone, duration in heart_rate_zones.items():
            print(f"Zone {zone}: {duration:.2f} seconds")

        print("\n--- Nutrition Information ---")
        # Add code to display nutrition information here
        print("Nutrition data display not yet implemented.")

