                        if "Strava" not in self.data:
                            self.data["Strava"] = []
                        self.data["Strava"].extend(new_data)
                        self.sources["Strava"] = [source] * len(new_data)
                        print(f"Successfully imported Strava data from {filepath}")
                    else:
                        print(f"No data imported from {filepath}")
                except Exception as e:
                    print(f"Error importing Strava data: {e}")

            elif source == "Polar Flow":
                # Placeholder for Polar Flow import logic
                # Replace with actual Polar Flow API integration or file parsing
                if module is None:
                    print("Error: Polar Flow module not provided.")
                    return
                try:
                    new_data = module.import_polar_data(filepath)
                    if new_data:
                        if "Polar Flow" not in self.data:
                            self.data["Polar Flow"] = []
                        self.data["Polar Flow"].extend(new_data)
                        self.sources["Polar Flow"] = [source] * len(new_data)
                        print(f"Successfully imported Polar Flow data from {filepath}")
                    else:
                        print(f"No data imported from {filepath}")
                except Exception as e:
