            else:
                print(f"Unsupported data source: {source}")

        except FileNotFoundError:
            print(f"Error: File not found at {filepath}")
        except Exception as e:
            print(f"An error occurred during import: {e}")

    def register_source_module(self, source, module):
        """Registers a module for a specific data source.

        Args:
            source (str): The name of the data source (e.g., "Strava").
            module (module): The module containing import functions.
        """
        self.source_modules[source] = module

    def aggregate_data(self):
        """Aggregates workout data from different sources into a single DataFrame."""
        all_data = []
        all_sources = []
        for source, data in self.data.items():
            if isinstance(data, list):
                all_data.extend(data)
                all_sources.extend(self.sources[source])
            else:
                print(f"Warning: Data from {source} is not a list and will be skipped.")

        if not all_data:
            print("No workout data available.")
            return None

        df = pd.DataFrame(all_data)
        df['source'] = all_sources
        return df

    def filter_by_sport(self, df, sport):
        """Filters the DataFrame by sport type."""
        if df is None:
            print("No data to filter.")
            return None
        return df[df["sport"] == sport]

    def calculate_total_mileage(self, df):
        """Calculates the total mileage from the DataFrame."""
        if df is None:
            print("No data to calculate mileage from.")
            return 0
        return df["distance"].sum()  # Assuming 'distance' column is in miles

    def calculate_heart_rate_zones(self, df):
        """Calculates the time spent in each heart rate zone."""
        if df is None:
            print("No data to calculate heart rate zones from.")
            return {}

        zone_times = {zone: datetime.timedelta() for zone in self.intensity_zones}

        for index, row in df.iterrows():
            if "heart_rate" in row and "duration" in row:
                heart_rate_data = row["heart_rate"]
                duration = row["duration"]

                if isinstance(heart_rate_data, list) and isinstance(duration, (int, float)):
                    # Assuming heart_rate_data is a list of heart rates and duration is total seconds
                    num_samples = len(heart_rate_data)
                    time_per_sample = duration / num_samples if num_samples > 0 else 0

                    for hr in heart_rate_data:
                        # Determine which zone the heart rate falls into
                        for zone, (lower, upper) in self.intensity_zones.items():
                            if lower <= hr <= upper:  # Assuming heart rate is normalized (0-1)
                                zone_times[zone] += datetime.timedelta(seconds=time_per_sample)
                                break  # Only assign to one zone

        return zone_times

    def plot_progress(self, df, metric="pace"):
        """Plots progress over time by pace or mileage."""
        if df is None:
            print("No data to plot.")
            return

        if df.empty:
            print("DataFrame is empty. No data to plot.")
            return

        if "date" not in df.columns:
