        if not workout.heart_rate_data:
            return {}

        zones = {"Zone 1": 0, "Zone 2": 0, "Zone 3": 0, "Zone 4": 0, "Zone 5": 0}
        last_timestamp = None
        last_bpm = None

        for timestamp, bpm in workout.heart_rate_data:
            if last_timestamp is not None:
                time_diff = timestamp - last_timestamp
                time_in_zone = time_diff.total_seconds() / 60  # in minutes

                if bpm < 120:  # Example zones, adjust as needed
                    zones["Zone 1"] += time_in_zone
                elif 120 <= bpm < 140:
                    zones["Zone 2"] += time_in_zone
                elif 140 <= bpm < 160:
                    zones["Zone 3"] += time_in_zone
                elif 160 <= bpm < 180:
                    zones["Zone 4"] += time_in_zone
                else:
                    zones["Zone 5"] += time_in_zone

            last_timestamp = timestamp
            last_bpm = bpm

        return zones

