                    pace = workout.duration / workout.distance  # minutes per km
                    data.append(pace)
                    dates.append(workout.date)
        elif metric == "mileage":
            # Aggregate mileage by time period
            if time_period == "weekly":
                weekly_mileage = {}
                for workout in self.workouts:
                    if workout.distance:
                        week_start = workout.date - datetime.timedelta(days=workout.date.weekday())
                        if week_start not in weekly_mileage:
                            weekly_mileage[week_start] = 0
                        weekly_mileage[week_start] += workout.distance
                dates = sorted(weekly_mileage.keys())
                data = [weekly_mileage[date] for date in dates]
            else:
                print("Only weekly mileage aggregation is supported.")
                return
        else:
            print("Invalid metric. Choose 'pace' or 'mileage'.")
            return

        # Create the plot
        plt.figure(figsize=(10, 6))
        plt.plot(dates, data, marker='o')
        plt.xlabel("Date")
        if metric == "pace":
            plt.ylabel("Pace (min/km)")
            plt.title("Progress by Pace")
        elif metric == "mileage":
            plt.ylabel("Mileage (km)")
            plt.title("Progress by Mileage")
        plt.grid(True)
        plt.xticks(rotation=45)
        plt.tight_layout()
        plt.show()

    def generate_dashboard(self):
        print("--- Workout Dashboard ---")
        for workout in self.workouts:
            print(workout)
            hr_zones = self.aggregate_heart_rate_zones(workout)
            if hr_zones:
