import pandas as pd
import matplotlib.pyplot as plt
import re

def clean_string(text):
    """
    Cleans a string by removing special characters and converting to lowercase.
    """
    if isinstance(text, str):
        return re.sub(r'[^a-zA-Z0-9\s]', '', text).lower()
    return text

def import_and_clean_data(file_path):
    """
    Imports data from a CSV file, cleans the column names and relevant data.
    """
    try:
        df = pd.read_csv(file_path)
    except FileNotFoundError:
        print(f"Error: File not found at {file_path}")
        return None
    except Exception as e:
        print(f"Error reading CSV: {e}")
        return None

    # Clean column names
    df.columns = [clean_string(col) for col in df.columns]

    # Clean relevant columns (example: activity type, sport, etc.)
    for col in df.columns:
        if df[col].dtype == 'object':  # Check if the column contains strings
            df[col] = df[col].apply(clean_string)

    return df

def filter_data(df, filter_criteria=None):
    """
    Filters the DataFrame based on specified criteria.
    """
    if df is None:
        return None

    filtered_df = df.copy()  # Start with a copy to avoid modifying the original

    if filter_criteria:
        for column, value in filter_criteria.items():
            if column in filtered_df.columns:
                filtered_df = filtered_df[filtered_df[column] == value]
            else:
                print(f"Warning: Column '{column}' not found in DataFrame.")

    return filtered_df

def analyze_heart_rate(df, heart_rate_column='averageheartrate'):
    """
    Calculates and displays basic heart rate statistics.
    """
    if df is None:
        return

    if heart_rate_column not in df.columns:
        print(f"Error: Heart rate column '{heart_rate_column}' not found.")
        return

    try:
        avg_hr = df[heart_rate_column].mean()
        max_hr = df[heart_rate_column].max()
        min_hr = df[heart_rate_column].min()

        print(f"Average Heart Rate: {avg_hr:.2f}")
        print(f"Maximum Heart Rate: {max_hr}")
        print(f"Minimum Heart Rate: {min_hr}")

    except TypeError:
        print("Error: Heart rate column contains non-numeric data.")
    except Exception as e:
        print(f"Error analyzing heart rate: {e}")

def visualize_data(df, x_axis, y_axis, plot_type='scatter', title='Data Visualization'):
    """
    Creates a plot of the data.
    """
    if df is None:
        return

    if x_axis not in df.columns or y_axis not in df.columns:
        print(f"Error: One or both of the specified axes ('{x_axis}', '{y_axis}') not found.")
        return

    try:
        plt.figure(figsize=(10, 6))  # Adjust figure size for better readability

        if plot_type == 'scatter':
            plt.scatter(df[x_axis], df[y_axis])
        elif plot_type == 'line':
            plt.plot(df[x_axis], df[y_axis])
        elif plot_type == 'bar':
            plt.bar(df[x_axis], df[y_axis])
        else:
            print("Error: Invalid plot type. Choose 'scatter', 'line', or 'bar'.")
            return

        plt.xlabel(x_axis)
        plt.ylabel(y_axis)
        plt.title(title)
        plt.grid(True)  # Add grid for easier reading
        plt.show()

    except TypeError:
        print("Error: One or both of the specified axes contain non-numeric data.")
    except Exception as e:
        print(f"Error creating plot: {e}")

def main():
    """
    Main function to orchestrate the data analysis process.
    """
    file_path = input("Enter the path to the CSV file: ")

    df = import_and_clean_data(file_path)

    if df is not None:
        print("\nData imported and cleaned successfully.")

        # Example filtering (you can customize this)
        filter_criteria = {}
        activity_type = input("Enter activity type to filter by (or leave blank for none): ")
        if activity_type:
            filter_criteria['activitytype'] = activity_type

        sport_type = input("Enter sport type to filter by (or leave blank for none): ")
        if sport_type:
            filter_criteria['sport'] = sport_type

        filtered_df = filter_data(df, filter_criteria)

        if filtered_df is not None and not filtered_df.empty:
