            x_axis = input("Enter the column name for the x-axis: ")
            y_axis = input("Enter the column name for the y-axis: ")
            plot_type = input("Enter the plot type (scatter, line, bar): ")
            visualize_data(filtered_df, x_axis, y_axis, plot_type)
        else:
            print("\nNo data found after filtering.")
    else:
